import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"API 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/api.md","filePath":"guide/architecture/api.md"}'),d={name:"guide/architecture/api.md"};function o(p,e,c,r,l,i){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="api-模块" tabindex="-1">API 模块 <a class="header-anchor" href="#api-模块" aria-label="Permalink to &quot;API 模块&quot;">​</a></h1><p><code>src/lab/api/</code> — HTTP 路由、外部服务客户端、模型加载。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api/</span></span>
<span class="line"><span>├── types.py             # 内部类型（FunASRModels / GlobalModelContainer）</span></span>
<span class="line"><span>├── routes/              # FastAPI 路由</span></span>
<span class="line"><span>│   ├── asr.py           # /asr — 语音识别（FunASR / Whisper）</span></span>
<span class="line"><span>│   ├── deeplx.py        # /translate — DeepLX 翻译代理</span></span>
<span class="line"><span>│   ├── faster_qwen_tts.py  # /tts/qwen-tts — Qwen-TTS 合成</span></span>
<span class="line"><span>│   ├── gpt_sovits.py    # GPT-SoVITS v1 路由</span></span>
<span class="line"><span>│   ├── gpt_sovits_v2.py # GPT-SoVITS v2 路由</span></span>
<span class="line"><span>│   └── vtuber.py        # VTuber WebSocket 入口</span></span>
<span class="line"><span>├── logic/               # 业务逻辑与模型封装</span></span>
<span class="line"><span>│   ├── funasr.py        # FunASRModel + 单例管理（load / reload / 推理封装）</span></span>
<span class="line"><span>│   ├── whisper.py       # WhisperModel + 单例管理（load / reload / 推理封装）</span></span>
<span class="line"><span>│   └── faster_qwen_tts.py  # Qwen-TTS 合成逻辑（单次 / 流式）</span></span>
<span class="line"><span>└── clients/             # 外部服务客户端</span></span>
<span class="line"><span>    ├── base_client_interface.py  # BaseRequest / BaseResponse / BaseClientInterface</span></span>
<span class="line"><span>    ├── asr_client.py        # ASRClient</span></span>
<span class="line"><span>    ├── gpt_sovits_client.py # GPTSoVITSClient</span></span>
<span class="line"><span>    ├── deeplx_client.py     # DeepLXClient</span></span>
<span class="line"><span>    ├── reload_client.py     # ReloadClient（模型热重载）</span></span>
<span class="line"><span>    └── vad_client.py        # VADClient</span></span></code></pre></div><h2 id="职责划分" tabindex="-1">职责划分 <a class="header-anchor" href="#职责划分" aria-label="Permalink to &quot;职责划分&quot;">​</a></h2><h3 id="routes-—-协议层" tabindex="-1">Routes — 协议层 <a class="header-anchor" href="#routes-—-协议层" aria-label="Permalink to &quot;Routes — 协议层&quot;">​</a></h3><p>路由只负责 HTTP 协议处理（参数解析、响应格式化），业务逻辑委托给 <code>logic/</code>。</p><table tabindex="0"><thead><tr><th>路由</th><th>前缀</th><th>功能</th></tr></thead><tbody><tr><td><code>asr.py</code></td><td><code>/asr</code></td><td>FunASR / Whisper 语音识别（带标点 / 不带标点 / VAD / 模型热重载）</td></tr><tr><td><code>deeplx.py</code></td><td><code>/translate/deeplx</code></td><td>DeepLX 翻译代理（调用外部服务）</td></tr><tr><td><code>faster_qwen_tts.py</code></td><td><code>/tts/qwen-tts</code></td><td>Qwen-TTS 语音合成（非流式 + SSE 流式）</td></tr><tr><td><code>gpt_sovits.py</code></td><td><code>/tts/gptsovits</code></td><td>GPT-SoVITS v1 TTS（JSON → base64 音频）</td></tr><tr><td><code>gpt_sovits_v2.py</code></td><td><code>/tts/gptsovitsv2</code></td><td>GPT-SoVITS v2 TTS（GET/POST → 音频文件，支持流式）</td></tr><tr><td><code>vtuber.py</code></td><td><code>/client-ws</code></td><td>Open-LLM-VTuber WebSocket 连接管理</td></tr></tbody></table><h3 id="logic-—-模型封装" tabindex="-1">Logic — 模型封装 <a class="header-anchor" href="#logic-—-模型封装" aria-label="Permalink to &quot;Logic — 模型封装&quot;">​</a></h3><p>每个文件对应一个模型，同时包含模型类定义和单例管理函数，职责内聚：</p><table tabindex="0"><thead><tr><th>文件</th><th>内容</th></tr></thead><tbody><tr><td><code>logic/funasr.py</code></td><td><code>FunASRModel</code>（asr / vad / asr_no_punc 三种子模型）+ <code>load_funasr</code> / <code>reload_funasr</code> / <code>funasr_asr_audio</code> / <code>funasr_vad_audio</code></td></tr><tr><td><code>logic/whisper.py</code></td><td><code>WhisperModel</code> + <code>load_whisper</code> / <code>reload_whisper</code> / <code>whisper_asr_audio</code></td></tr><tr><td><code>logic/faster_qwen_tts.py</code></td><td>Qwen-TTS 合成逻辑（单次 / 流式）</td></tr></tbody></table><p>FunASR 与 Whisper 完全解耦，<code>server.py</code> 启动时各自按 <code>[package]</code> flag 独立预加载，互不干扰。</p><h3 id="clients-—-外部服务封装" tabindex="-1">Clients — 外部服务封装 <a class="header-anchor" href="#clients-—-外部服务封装" aria-label="Permalink to &quot;Clients — 外部服务封装&quot;">​</a></h3><p>所有 Client 继承 <code>BaseClientInterface</code>，统一了请求/响应模型和日志。用于从 <code>conversations/</code> 等内部模块调用 TTS、ASR 等服务。</p><h2 id="与其他模块的关系" tabindex="-1">与其他模块的关系 <a class="header-anchor" href="#与其他模块的关系" aria-label="Permalink to &quot;与其他模块的关系&quot;">​</a></h2><ul><li><strong>server.py</strong> 挂载路由：<code>deeplx_router</code>、<code>qwen_tts_router</code>、<code>vtuber_router</code></li><li><strong>conversations/</strong> 通过 Clients 调用 TTS / 翻译</li><li><strong>agent/</strong> 不直接依赖 api/，而是通过 conversations 层间接使用</li></ul>`,16)])])}const _=a(d,[["render",o]]);export{u as __pageData,_ as default};
